window.FREENAV_COLUMNS=[{key:"opensource-alt",title:"开源 / 免费替代库",icon:"♻️",axis:"替代对比表 · 逐项打分",tagline:"别人花几千块买的，这些免费的其实更好用",intro:"破解有风险、订阅是持续的税。这一栏把「开源 / 免费 替代 付费」的成熟方案集中起来，配一张对比表，让你一眼看清每个免费方案能替代谁、差在哪。结论先行：日常 90% 场景，免费方案已经够用。",picks:{ids:["gimp","libreoffice","jellyfin","darktable","krita","inkscape","blender","obs","bitwarden","ollama","stirlingpdf","obsidian","joplin"]},compare:[{name:"GIMP",vs:"Adobe Photoshop",price:"开源免费",platforms:"Win·Mac·Linux",note:"图层/抠图/修复够用；商业精修、CMYK 印刷前处理偏弱"},{name:"LibreOffice",vs:"Microsoft Office",price:"开源免费",platforms:"三平台",note:"兼容 docx/xlsx/pptx；宏与高级排版略有差距"},{name:"Jellyfin",vs:"Netflix / Plex",price:"开源免费",platforms:"全平台 + 自托管",note:"自建私人影音库，无订阅、无内容限制"},{name:"Darktable",vs:"Adobe Lightroom",price:"开源免费",platforms:"三平台",note:"非破坏性 RAW 后期，专业摄影可用"},{name:"Krita",vs:"Clip Studio / Procreate",price:"开源免费",platforms:"三平台 + 安卓",note:"插画/概念图，笔刷生态成熟"},{name:"Inkscape",vs:"Adobe Illustrator",price:"开源免费",platforms:"三平台",note:"矢量 SVG，Logo / 插画首选"},{name:"Blender",vs:"Maya / C4D",price:"开源免费",platforms:"三平台",note:"全流程 3D，建模到渲染一体"},{name:"OBS Studio",vs:"商业录屏 / 直播",price:"开源免费",platforms:"三平台",note:"直播录屏行业标配"},{name:"Bitwarden",vs:"1Password",price:"开源 / 免费增值",platforms:"全平台",note:"端到端加密密码管理，自建服务端可选"},{name:"Ollama",vs:"ChatGPT Plus",price:"开源免费",platforms:"Mac·Linux·Win",note:"本地大模型，隐私可控、零订阅"},{name:"Stirling-PDF",vs:"小型 PDF 工具箱",price:"开源免费",platforms:"Web / 自托管",note:"合并/拆分/转换一站搞定"},{name:"Obsidian / Joplin",vs:"Notion / Evernote",price:"免费增值 / 开源",platforms:"全平台",note:"本地优先笔记与知识库，数据自己掌控"}],reviews:[{title:"GIMP 真能替代 Photoshop 吗？8 个高频场景实测",rating:4.3,difficulty:"中等",bestFor:"日常修图、社媒配图、电商图、简单合成；预算敏感的个人与小型团队",notFor:"商业级精修、CMYK 印刷前处理、依赖 PS 专属插件/动作的工作流",pros:["永久免费、全平台、开源可审计，零订阅成本","图层/图层组/图层蒙版思路与 PS 一致，迁移成本低","社区插件 G'MIC 滤镜极强（降噪/修复/艺术效果）","支持 PSD 导入与导出（复杂图层样式会丢信息）"],cons:["无原生 CMYK，印刷前处理需借 Scribus 或 Krita","发丝级精细抠图弱于 PS「选择并遮住」","字体渲染与段落控制不如 PS/AI，专业排版别指望","批处理要写 Script-Fu / Python，门槛高于 PS 动作"],verdict:"对 80% 用户，省下的订阅费比那 20% 差距更值；真卡在商业工作流时，再买断 Affinity Photo（约 ¥300）比订阅 PS 划算。",body:"<p>GIMP（当前稳定版 2.10/3.0 系列）是开源圈最常被拿来和 Photoshop 比的修图工具。结论先说：<strong>日常修图、社媒配图、简单合成，它完全够用；商业精修、印刷前处理、超复杂合成，仍建议 PS 或 Affinity Photo。</strong>下面是 8 个真实场景的实测。</p><h4>① 图层与蒙版</h4><p>支持多图层、图层组、图层蒙版，和 PS 思路一致；非破坏性编辑靠「图层组 + 蒙版」组合实现，迁移成本不高。</p><h4>② 选区与抠图</h4><p>快速蒙版、路径、色彩选区都有；发丝级精细抠图比 PS 的「选择并遮住」弱一点，但配合「前景选择」工具基本能解决日常需求。</p><h4>③ 修复画笔 / 污点修复</h4><p>「修复」与「克隆」工具齐备，去水印、祛痘、去杂物日常够用。</p><h4>④ RAW 与 Camera Raw</h4><p>GIMP 本身不吃 RAW，需要装 <strong>Darktable</strong> 或 <strong>RawTherapee</strong> 转档后再进 GIMP，多了一步——专业摄影建议 Darktable 做主后期。</p><h4>⑤ 文字与排版</h4><p>能做简单海报文字，但字体渲染、段落控制不如 PS/AI，长文排版请用 Scribus。</p><h4>⑥ 滤镜与插件生态</h4><p>自带滤镜够基础；社区插件 <strong>G'MIC</strong> 很强（降噪、修复、艺术化），但整体生态规模远不及 PS 插件市场。</p><h4>⑦ 批处理 / 自动化</h4><p>支持 Script-Fu（Scheme）和 Python-Fu，批量水印建议配合 ImageMagick 写脚本，比 PS 动作门槛高。</p><h4>⑧ 成本对比</h4><p>Photoshop 订阅约 ¥888/年；GIMP 永久免费、全平台、开源可审计。<strong>对个人与小微团队，省下的订阅费通常比那 20% 功能差距更值。</strong></p><p class='review-tip'>建议路径：先用 GIMP 省预算；当你明确卡在某个商业工作流（如印刷厂要求 CMYK、客户指定 PS 工程）时，再考虑一次性买断的 Affinity Photo，比订阅 PS 划算得多。</p>"},{title:"免费替代怎么选：一张决策表",rating:4.5,difficulty:"低",bestFor:"想系统替换付费软件、又怕踩坑的个人与团队",notFor:"必须使用特定闭源专有格式 / 插件的强协作场景",pros:["一次性迁移成本低，多数工具兼容主流格式（docx/svg/psd 导入）","数据自持，不绑定厂商，迁移自由","社区活跃，教程多，问题易搜"],cons:["团队强协同时，部分工具实时协作弱于商业 SaaS","极端专业需求仍需商业软件补位"],verdict:"日常办公/修图/影音/密码/AI 全可用免费方案覆盖；把省下的订阅费投到硬件或正版专业软件上，性价比最高。",body:"<p>不想一个个试？按「你在用哪个付费软件」直接对照：</p><h4>办公</h4><p>Office → LibreOffice / OnlyOffice（兼容 docx，学校机房多为正版 Office 时优先用学校的）。</p><h4>笔记</h4><p>Notion / 有道云笔记 → Obsidian（本地优先、双链）/ Joplin（端到端加密、多端同步）。</p><h4>密码</h4><p>1Password → Bitwarden（开源，可自建服务端）。</p><h4>修图</h4><p>Photoshop → GIMP；Lightroom → Darktable；插画 → Krita。</p><h4>影音</h4><p>Netflix/Plex → Jellyfin（自托管，无订阅）。</p><h4>AI</h4><p>ChatGPT Plus → Ollama（本地模型，隐私可控）。</p><p class='review-tip'>通用原则：先用免费方案跑通 90% 工作；只有当某个具体功能真的卡住，再为那 10% 单独买断专业软件，而不是为 10% 常年订阅全家桶。</p>"}]},{key:"newbie",title:"新人装机清单",icon:"🎒",axis:"装机清单 · 照着装",tagline:"刚装好系统？照这份清单装完，电脑立刻好用一倍",intro:"学生、职场新人、刚重装系统的电脑，最容易被「破解版」坑（带毒、弹窗、丢文件）。这一栏按真实使用场景（写文档、做 PPT、记笔记、传文件、录网课）挑免费正版方案，全部开源 / 官方免费，安全无坑，照着装完即用好用。",picks:{ids:["libreoffice","onlyoffice","obsidian","joplin","marktext","bitwarden","stirlingpdf","obs","localsend","everything","sharex","flowlauncher","anki","zotero"]},compare:[{name:"LibreOffice",vs:"Microsoft Office",price:"开源免费",platforms:"三平台",note:"写论文 / 做 PPT 首选，兼容 docx/pptx"},{name:"OnlyOffice",vs:"WPS / Office",price:"开源免费",platforms:"三平台 + Web",note:"界面现代，协作与格式兼容好"},{name:"Obsidian / Joplin",vs:"有道云笔记 / Notion",price:"免费 / 开源",platforms:"全平台",note:"笔记 + 知识库，本地优先不丢"},{name:"Bitwarden",vs:"付费密码器",price:"开源免费",platforms:"全平台",note:"统一管理学号 / 邮箱 / 各类账号密码"},{name:"Stirling-PDF",vs:"PDF 编辑会员",price:"开源免费",platforms:"Web",note:"合并 / 拆分 / 去水印，交作业常用"},{name:"OBS Studio",vs:"录屏软件",price:"开源免费",platforms:"三平台",note:"录制网课、答辩演示、线上分享"},{name:"LocalSend",vs:"网盘 / 微信传文件",price:"开源免费",platforms:"全平台",note:"宿舍局域网高速互传，不限速"},{name:"MarkText",vs:"Typora（付费）",price:"开源免费",platforms:"三平台",note:"Markdown 写作，课程小结 / 实验报告"}],reviews:[{title:"上大学前装好这 14 款免费正版软件（附难度与用途）",rating:4.7,difficulty:"低",bestFor:"本科生 / 研究生自用电脑的「基础装备」；想避开破解版与订阅陷阱",notFor:"学校强制指定某商业软件且必须交工程文件的课程（先用学校正版授权）",pros:["全免费、无广告、无弹窗，安全可审计","数据本地优先，毕业多年后仍能打开","覆盖写论文/做PPT/记笔记/传文件/录屏全链路"],cons:["个别课程要求特定商业软件格式时需临时借用学校机房","实时多人协作弱于商业 SaaS（可用 OnlyOffice 缓解）"],verdict:"先把这 14 款装好，大学四年 90% 的软件需求不用再花钱；涉及学校正版授权（很多高校免费 Office 365 / 正版 MATLAB）先问学校 IT，别重复买。",body:"<p>按大学四年真实会遇到的任务，整理一份「免费正版」装备清单。都不是试用版、都不弹广告、都不带毒。难度分 易 / 中 / 难。</p><h4>写作与文档（易）</h4><ul><li><strong>LibreOffice / OnlyOffice</strong>：替代 Word/Excel/PPT，交作业零兼容焦虑。</li><li><strong>MarkText</strong>：课程小结、实验报告用 Markdown 写更清爽（替代 Typora）。</li><li><strong>Stirling-PDF</strong>：合并课件、拆分 PDF、去水印，交作业高频需求。</li></ul><h4>笔记与知识管理（易~中）</h4><ul><li><strong>Obsidian</strong>：本地双链笔记，适合搭个人知识库，毕业多年后文件仍在。</li><li><strong>Joplin</strong>：端到端加密 + 多端同步，怕丢笔记选它。</li><li><strong>Zotero</strong>：一键抓取论文、生成引用，写文献综述神器。</li></ul><h4>账号与安全（易）</h4><ul><li><strong>Bitwarden</strong>：学号、邮箱、各种平台密码统一管理，别再全校共用一个密码。</li></ul><h4>协作与传输（易）</h4><ul><li><strong>LocalSend</strong>：宿舍 / 实验室局域网互传大文件，比微信和某盘都快。</li><li><strong>OBS Studio</strong>：录网课、录屏幕演示、线上答辩共享，开源无限制。</li></ul><h4>效率与系统（易~中）</h4><ul><li><strong>Everything</strong>：秒搜本地文件，找课件 / 往届卷子快到飞起。</li><li><strong>ShareX</strong>：截图 + 长截图 + 录屏 + OCR，做 PPT 找素材利器。</li><li><strong>Flow Launcher</strong>：类 Alfred 启动器，开软件、算公式、查单词一键直达。</li><li><strong>Anki</strong>：间隔重复记忆卡，背单词 / 备考，难度 中（要自己维护卡片）。</li></ul><p class='review-tip'>提醒：很多高校提供免费正版 Office 365、甚至 MATLAB/Adobe 教育授权，先问学校 IT 部门再决定要不要装开源替代，别重复花钱。涉及学校统一平台的作业，优先用学校指定的格式提交。</p>"}]},{key:"design",title:"设计师免费素材全家桶",icon:"🎨",axis:"工具 + 可商用素材",tagline:"不花一分钱的设计流水线：工具 + 可商用素材",intro:"设计不一定要 Adobe 全家桶。这一栏汇集开源设计工具，并告诉你 8 类常用素材（图标、字体、配色、图片、3D…）去哪找正版免费资源，配齐「工具 + 素材」，从接单到作品集都能跑通。",picks:{ids:["gimp","inkscape","krita","blender","darktable","audacity","obs","shotcut","scribus","pencil2d","fontforge"]},compare:[{name:"GIMP",vs:"Photoshop",price:"开源免费",platforms:"三平台",note:"修图 / 合成 / 电商图"},{name:"Inkscape",vs:"Illustrator",price:"开源免费",platforms:"三平台",note:"矢量 Logo / 插画 / 印刷稿"},{name:"Krita",vs:"Procreate / Clip",price:"开源免费",platforms:"多端",note:"插画 / 概念图 / 板绘"},{name:"Darktable",vs:"Lightroom",price:"开源免费",platforms:"三平台",note:"RAW 调色 / 摄影后期"},{name:"Blender",vs:"C4D / Maya",price:"开源免费",platforms:"三平台",note:"3D / 动效 / 产品图"},{name:"Scribus",vs:"InDesign",price:"开源免费",platforms:"三平台",note:"排版印刷级，小册子 / 海报"},{name:"FontForge",vs:"Glyphs / FontLab",price:"开源免费",platforms:"三平台",note:"改字 / 做像素字体"}],reviews:[{title:"免费设计素材去哪找？8 类资源 + 授权避坑",rating:4.6,difficulty:"低",bestFor:"独立设计师、学生、自媒体；需要「商用不踩版权雷」的正版免费素材",notFor:"对素材有独家 / 署名要求的品牌项目（建议采购商业授权）",pros:["CC0 / MIT / SIL OFL 等授权可商用、多数无需署名","工具全免费，从修图到 3D 到排版一条龙","素材站资源丰富，更新快"],cons:["热门素材易「撞图」，需二次创作拉开差异","部分 CC0 图库质量参差，需筛选"],verdict:"工具免费了，素材也要「可商用」才安心。按下方清单取用，商用前确认授权类型并保留署名要求（若注明），不确定就别用。",body:"<p>工具免费了，素材也要正版免费才安心（商用不踩版权雷）。按使用频率排 8 类，并标注推荐授权与配套工具：</p><h4>① 图标（MIT / CC0）</h4><p>优先 SVG 开源图标库，可改色改线条；本站 <strong>Inkscape</strong> 也能自绘专属图标。</p><h4>② 插画 / 配图（CC0）</h4><p>找可商用插画站用于海报、推文封面；手绘风用 <strong>Krita</strong> 自制，避免撞图。</p><h4>③ 字体（SIL OFL 可商用）</h4><p>用开源字体规避「微软雅黑商用」类雷区；改字体用 <strong>FontForge</strong> 做像素/装饰字体。</p><h4>④ 配色</h4><p>用开源配色工具生成对比度达 WCAG 标准的色板，导出给 Figma / CSS。</p><h4>⑤ 图片 / 照片（CC0）</h4><p>搜索时勾选「可商用 / 无需署名」；电商图用 <strong>GIMP</strong> 抠图合成。</p><h4>⑥ 3D 模型（CC0）</h4><p>找 CC0 模型做占位 / 参考；正式产出用 <strong>Blender</strong> 重拓扑更可控。</p><h4>⑦ UI / 界面套件</h4><p>用开源设计系统组件，别从零造轮子；导出资源配合 <strong>Inkscape</strong> 微调。</p><h4>⑧ 音效 / 视频（CC0）</h4><p>找 CC0 音效库配动效与短片；剪辑用 <strong>Shotcut</strong>，录屏用 <strong>OBS</strong>。</p><p class='review-tip'>版权红线：商用前确认授权是 CC0 / MIT / SIL OFL 等「可商用」许可，并保留署名要求（若注明）。不确定就别用，宁可用工具自己生成的。收到客户素材也要确认其授权链。</p>"}]},{key:"local-ai",title:"本地 AI 工具箱",icon:"🤖",axis:"本地部署教程",tagline:"把大模型装进自己电脑，零订阅、隐私不出本机",intro:"云端 AI 要订阅、要看隐私政策、会限流。这一栏聚焦「本地优先」的开源 AI：模型在你机器上跑，数据不出本机，一次部署长期免费。配一张能力对比表，和一份零成本部署指南。",picks:{ids:["ollama","lmstudio","openwebui","comfyui","jan","anythingllm","upscayl","whisper","sdwebui","pinokio","localai","obsidian"]},compare:[{name:"Ollama",vs:"ChatGPT Plus",price:"开源免费",platforms:"Mac·Linux·Win",note:"本地对话 / 推理，隐私可控零订阅"},{name:"LM Studio",vs:"云端 GUI",price:"免费",platforms:"三平台",note:"图形化下载 / 聊天 / 本地 API"},{name:"Stable Diffusion WebUI",vs:"Midjourney",price:"开源免费",platforms:"自托管（需独显）",note:"文生图，提示词可控、可炼 LoRA"},{name:"ComfyUI",vs:"SD 网页版",price:"开源免费",platforms:"Win·Linux",note:"节点式工作流，出图可复现"},{name:"Whisper",vs:"商业转录",price:"开源免费",platforms:"全平台",note:"本地语音转文字，字幕 / 会议纪要"},{name:"Open WebUI",vs:"云端 AI 前端",price:"开源免费",platforms:"Web / 自托管",note:"给本地模型一个好看的聊天界面"},{name:"AnythingLLM",vs:"云端知识库",price:"开源免费",platforms:"全平台 + 自托管",note:"本地知识库 + RAG，喂文档给私有 GPT"},{name:"LocalAI",vs:"云端推理 API",price:"开源免费",platforms:"自托管",note:"OpenAI 兼容接口，消费级硬件可跑"}],reviews:[{title:"把大模型跑在自己电脑上：Ollama + 开源模型零成本指南",rating:4.5,difficulty:"中等",bestFor:"在意隐私、不想月月交订阅、想本地跑 7B~14B 模型的个人用户",notFor:"没有独显且内存 < 8GB、只想开箱即用的轻度用户（先用云端免费额度）",pros:["数据不出本机，隐私可控","一次部署，长期零订阅","模型生态丰富（Qwen / Llama / Mistral 等），可换可炼"],cons:["需要基本命令行操作（拉模型、起服务）","无独显时只能跑小模型，速度慢","「联网搜索 / 插件」功能仍可能外发请求"],verdict:"不想每月给 AI 交订阅、又担心聊天记录被拿去训练？本地部署是最干净的方案。硬件一次性投入，之后零订阅、数据不出本机。",body:"<p>不想每月给 AI 交订阅、又担心聊天记录被拿去训练？本地部署是最干净的方案。以 <strong>Ollama</strong> 为例，门槛比你想象低。</p><h4>第一步：安装</h4><p>去 Ollama 官网下对应系统安装包，装完终端里 <code>ollama --version</code> 能出版本号即成功（Windows/Mac 有安装包，Linux 一行命令）。</p><h4>第二步：拉一个模型</h4><p>中文场景推荐先拉 <code>qwen2.5</code> 或 <code>llama3</code>：<code>ollama run qwen2.5:7b</code>。7B 量级在 16G 内存的笔记本就能跑，够日常问答；想要更强上 14B（需更多内存）。</p><h4>第三步：命令行对话</h4><p>上一步跑起来直接在终端聊天。想图形界面，再装 <strong>Open WebUI</strong>（一条 Docker 命令），体验接近 ChatGPT；怕命令行可先用 <strong>LM Studio</strong> 图形端。</p><h4>第四步：进阶玩法</h4><ul><li><strong>Whisper</strong> 本地转写会议 / 网课录音成文字稿（模型 tiny/base 足够日常）；</li><li><strong>Stable Diffusion WebUI</strong> 本地出图（需要一张独显，8G 显存起步跑 1.5 模型）；</li><li><strong>AnythingLLM</strong> 把 PDF / 笔记变成可问答的私人知识库（RAG）；</li><li><strong>Obsidian + 本地向量插件</strong> 把笔记变成可检索的私人知识库。</li></ul><h4>硬件与成本</h4><p>纯 CPU 也能跑小模型，只是慢；想要流畅，加一块二手独显最划算（8~12G 显存可跑 7B~14B 对话 + 出图）。算总账：<strong>一次性硬件投入，之后零订阅、数据不出本机</strong>。</p><p class='review-tip'>安全提醒：本地模型不会把数据上传，但「联网搜索 / 插件」类功能仍可能外发请求。敏感内容请在离线模式下使用，且不要给本地服务暴露到公网（除非做好鉴权）。</p>"},{title:"本地 AI 工具怎么选：对话 / 出图 / 知识库三张对照",rating:4.4,difficulty:"中等",bestFor:"想搭一套本地 AI 工作流、又不确定用哪款的新手",notFor:"只想要一个聊天窗口、不想碰配置的轻度用户",pros:["覆盖对话 / 出图 / 知识库全场景","全部开源免费，可组合使用"],cons:["工具多，选择成本高","出图类对硬件（独显）有要求"],verdict:"对话用 Ollama + Open WebUI；出图用 SD WebUI / ComfyUI（需独显）；知识库用 AnythingLLM。三者可并存，互不冲突。",body:"<p>本地 AI 工具很多，按用途分三块就不会乱：</p><h4>对话 / 推理</h4><p><strong>Ollama</strong>（命令行/轻量）或 <strong>LM Studio</strong>（图形端）拉模型；想要漂亮界面加 <strong>Open WebUI</strong>；想要 OpenAI 兼容 API 用 <strong>LocalAI</strong>。</p><h4>文生图</h4><p><strong>Stable Diffusion WebUI（AUTOMATIC1111）</strong> 生态最大、教程最多；<strong>ComfyUI</strong> 节点式、可复现工作流，适合进阶。两者都吃独显。</p><h4>知识库 / RAG</h4><p><strong>AnythingLLM</strong> 开箱即用，把文档喂给本地模型问答；配合 <strong>Obsidian</strong> 做个人知识管理。</p><p class='review-tip'>新手路线：先 Ollama + Open WebUI 跑通对话 → 再按需要加 Whisper（转写）/ AnythingLLM（知识库）→ 有独显再上 SD WebUI 出图。别一上来全装，按需扩展。</p>"}]}];